const realm = '${full_index_realm}';
const inFlight = Number((context.panel.elements.find(function(e){return e.id==='in_flight';})||{}).value || 0);
const pending = Number((context.panel.elements.find(function(e){return e.id==='pending';})||{}).value || 0);
const oldest = (context.panel.elements.find(function(e){return e.id==='oldest_pending_human';})||{}).value || 'n/a';
if (inFlight > 0) {
  context.grafana.notifyWarning(['Reindex blocked', 'An indexing job is already in flight for this realm. Wait for it to finish before triggering a new one.']);
  return;
}
if (!window.confirm('Reindex ' + realm + '?\n\nBlast radius:\n  pending: ' + pending + '\n  oldest pending: ' + oldest + '\n\nThis will queue a from-scratch index for the selected realm only.')) { return; }
try {
  const r = await fetch('${realm_server}_grafana-reindex?realm=' + encodeURIComponent(realm), { method: 'POST', headers: { 'Authorization': 'Bearer ${grafana_secret}' } });
  if (r.ok) {
    context.grafana.notifySuccess(['Reindex queued', 'Started reindex of ' + realm]);
    if (typeof context.grafana.refresh === 'function') { context.grafana.refresh(); }
  } else {
    const txt = await r.text();
    context.grafana.notifyError(['Reindex failed', 'HTTP ' + r.status + ': ' + txt]);
  }
} catch (err) {
  context.grafana.notifyError(['Reindex failed', String(err)]);
}

const pendingFull = Number((context.panel.elements.find(function(e){return e.id==='pending_full_reindex';})||{}).value || 0);
if (pendingFull > 0) {
  context.grafana.notifyWarning(['Full reindex blocked', 'A full-reindex job is already pending or running. Wait for it to finish before triggering another.']);
  return;
}
if (!window.confirm('Reindex ALL realms?\n\nThis kicks off an indexing job for every realm on the server and can take a long time.')) { return; }
try {
  const r = await fetch('${realm_server}_grafana-full-reindex', { method: 'POST', headers: { 'Authorization': 'Bearer ${grafana_secret}' } });
  if (r.ok) {
    context.grafana.notifySuccess(['Full reindex queued', 'Started reindex of all realms.']);
    if (typeof context.grafana.refresh === 'function') { context.grafana.refresh(); }
  } else {
    const txt = await r.text();
    context.grafana.notifyError(['Full reindex failed', 'HTTP ' + r.status + ': ' + txt]);
  }
} catch (err) {
  context.grafana.notifyError(['Full reindex failed', String(err)]);
}
